-- Restore the Resources.Data RSA blob (Keys.snk) for the demo product.
-- The licenses.sql dump stored the binary blob as text and the UTF-8 round-trip
-- corrupted it, which caused license signing to fail with
-- "n does not equal p q". This file runs after licenses.sql and overwrites
-- the corrupted blob with the bytes from Keys.snk.
USE licenses;
UPDATE Resources SET Data = _binary  WHERE Id = 1;
